package com.socialblog.comment.application;import com.socialblog.comment.domain.OutboxEvent;import com.socialblog.comment.repository.OutboxEventRepository;import org.junit.jupiter.api.Test;import org.springframework.kafka.core.KafkaTemplate;import java.time.Instant;import java.util.*;import java.util.concurrent.CompletableFuture;import static org.assertj.core.api.Assertions.assertThat;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class OutboxPublisherTest{@Test void publishesAfterAcknowledgement(){OutboxEventRepository r=mock(OutboxEventRepository.class);@SuppressWarnings("unchecked")KafkaTemplate<String,String>k=mock(KafkaTemplate.class);OutboxEvent e=event();when(r.lockPendingBatch(50)).thenReturn(List.of(e));when(k.send(anyString(),anyString(),anyString())).thenReturn(CompletableFuture.completedFuture(null));new OutboxPublisher(r,k,"comments.events",50,3).publish();assertThat(e.getStatus()).isEqualTo(OutboxEvent.Status.PUBLISHED);}@Test void failsAtAttemptLimit(){OutboxEventRepository r=mock(OutboxEventRepository.class);@SuppressWarnings("unchecked")KafkaTemplate<String,String>k=mock(KafkaTemplate.class);OutboxEvent e=event();when(r.lockPendingBatch(50)).thenReturn(List.of(e));when(k.send(anyString(),anyString(),anyString())).thenReturn(CompletableFuture.failedFuture(new RuntimeException()));OutboxPublisher p=new OutboxPublisher(r,k,"comments.events",50,2);p.publish();p.publish();assertThat(e.getStatus()).isEqualTo(OutboxEvent.Status.FAILED);assertThat(e.getAttempts()).isEqualTo(2);}private OutboxEvent event(){UUID id=UUID.randomUUID();return new OutboxEvent(id,id,"CommentCreated","{}",Instant.now());}}
